class Solution:
    def sumSubarrayMins(self, arr):
        MOD = 10**9 + 7
        n = len(arr)
        total = 0
        for i in range(n):
            mn = arr[i]
            for j in range(i, n):
                mn = min(mn, arr[j])
                total += mn
        return total % MOD

