var sumSubarrayMins = function(arr) {
    const MOD = 1000000007n;
    const n = arr.length;
    const left = new Array(n).fill(0);
    const right = new Array(n).fill(0);
    let stack = [];
    for (let i = 0; i < n; i++) {
        while (stack.length && arr[stack[stack.length-1]] >= arr[i]) stack.pop();
        left[i] = stack.length === 0 ? i + 1 : i - stack[stack.length-1];
        stack.push(i);
    }
    stack = [];
    for (let i = n - 1; i >= 0; i--) {
        while (stack.length && arr[stack[stack.length-1]] > arr[i]) stack.pop();
        right[i] = stack.length === 0 ? n - i : stack[stack.length-1] - i;
        stack.push(i);
    }
    let total = 0n;
    for (let i = 0; i < n; i++) {
        total = (total + BigInt(arr[i]) * BigInt(left[i]) * BigInt(right[i])) % MOD;
    }
    return Number(total);
};
